graphql.query:
query InspectMutationArgs {
    __type(name: "Mutation") {
      fields {
        name
        args {
          name
          type {
            name
            kind
            ofType { name kind }
          }
        }
      }
    }
  }

query ListProjectTokens($projectId: String!) {
    projectTokens(projectId: $projectId) {
      edges {
        node {
          id
          name
          createdAt
        }
      }
    }
  }

query InspectInput {
    __type(name: "ProjectTokenInput") {
      name
      inputFields {
        name
        description
        type { name kind ofType { name kind ofType { name kind } } }
      }
    }
  }

query GetProject($id: String!) {
  project(id: $id) {
    id
    name
    workspace { id name }
    environments {
      edges { node { id name } }
    }
    services {
      edges {
        node {
          id
          name
          serviceInstances {
            edges {
              node {
                environmentId
                latestDeployment { id status }
              }
            }
          }
        }
      }
    }
  }
}

query ServiceInstance($serviceId: String!, $environmentId: String!) {
  serviceInstance(serviceId: $serviceId, environmentId: $environmentId) {
    serviceId
    environmentId
    startCommand
    numReplicas
    region
    restartPolicyType
    latestDeployment { id status createdAt }
  }
}

mutation serviceUpdate($id: String!, $input: ServiceUpdateInput!) {
serviceUpdate(id: $id, input: $input) {
  id
  name
  icon
}
}

query GetTemplate($code: String!) {
  template(code: $code) {
    id
    name
    serializedConfig
  }
}

query Deployments($projectId: String!, $serviceId: String!, $environmentId: String!) {
  deployments(
    input: {
      projectId: $projectId,
      serviceId: $serviceId,
      environmentId: $environmentId
    }
    first: 5
  ) {
    edges {
      node {
        id
        status
        createdAt
        staticUrl
      }
    }
  }
}

mutation RedeployDeployment($id: String!) {
  deploymentRedeploy(id: $id) {
    id
    status
  }
}
